// ════════════════════════════════════════════════════════
// BUDGET ENGINE (JS) — simulate / mutate du JSON budget
// ════════════════════════════════════════════════════════
let input;
try {
  input = typeof query === 'string' ? JSON.parse(query) : query;
} catch (e) {
  return JSON.stringify({ error: 'JSON d\'entrée invalide : ' + e.message });
}

const simulate = input.simulate !== false; // défaut : simulate=true (sécurité)
const operations = Array.isArray(input.operations) ? input.operations : [];
const anneeTarget = input.annee || new Date().getFullYear();

// Récupère finance_data depuis le contexte du workflow
const normalized = $('Normalize Input').first().json;
const financeData = normalized.finance_data ? JSON.parse(JSON.stringify(normalized.finance_data)) : null;

if (!financeData) {
  return JSON.stringify({
    error: 'Aucun finance_data dans la requête actuelle. L\'utilisateur doit relancer via l\'interface web.'
  });
}

// Snapshot "Avant"
const snapshot = (d, annee) => {
  const y = d.donneesAnnuelles && d.donneesAnnuelles[annee];
  if (!y) return null;
  const sum = obj => Object.values(obj || {}).reduce((s, v) => s + (Number(v && v.valeur) || Number(v && v.base) || 0), 0);
  return {
    revenus: sum(y.revenus),
    fixes: sum(y.chargesFixes),
    variables: sum(y.chargesVariables),
    epargne: sum(y.epargne),
    depensesIrreg: (y.depensesIrregulieres || []).length
  };
};

const before = snapshot(financeData, anneeTarget);
const log = [];

// Applique les opérations
for (const op of operations) {
  const y = financeData.donneesAnnuelles && financeData.donneesAnnuelles[op.annee || anneeTarget];
  if (!y) { log.push({ op, status: 'skip', reason: 'année absente' }); continue; }
  try {
    if (op.type === 'set_charge_fixe' && y.chargesFixes && y.chargesFixes[op.key]) {
      const old = y.chargesFixes[op.key].valeur;
      y.chargesFixes[op.key].valeur = Number(op.valeur);
      log.push({ op: op.type, key: op.key, avant: old, apres: Number(op.valeur) });
    } else if (op.type === 'set_revenu' && y.revenus && y.revenus[op.key]) {
      const old = y.revenus[op.key].base;
      y.revenus[op.key].base = Number(op.base);
      log.push({ op: op.type, key: op.key, avant: old, apres: Number(op.base) });
    } else if (op.type === 'set_epargne' && y.epargne && y.epargne[op.key]) {
      const old = y.epargne[op.key].valeur;
      y.epargne[op.key].valeur = Number(op.valeur);
      log.push({ op: op.type, key: op.key, avant: old, apres: Number(op.valeur) });
    } else if (op.type === 'add_depense_ponctuelle') {
      if (!Array.isArray(y.depensesIrregulieres)) y.depensesIrregulieres = [];
      y.depensesIrregulieres.push({
        id: Date.now() + Math.floor(Math.random() * 1000),
        mois: Number(op.mois), annee: Number(op.annee || anneeTarget),
        nom: String(op.nom), montant: Number(op.montant),
        paye: false, montantPaye: 0
      });
      log.push({ op: op.type, nom: op.nom, montant: Number(op.montant) });
    } else {
      log.push({ op, status: 'skip', reason: 'type inconnu ou clé absente' });
    }
  } catch (e) {
    log.push({ op, status: 'error', reason: e.message });
  }
}

// Validation structurelle
const valid = financeData.donneesAnnuelles && typeof financeData.donneesAnnuelles === 'object' &&
              financeData.soldesInitiaux && typeof financeData.soldesInitiaux === 'object';

const after = snapshot(financeData, anneeTarget);

const result = {
  mode: simulate ? 'SIMULATION' : 'APPLY',
  valid,
  annee: anneeTarget,
  avant: before,
  apres: after,
  delta: before && after ? {
    revenus: after.revenus - before.revenus,
    fixes: after.fixes - before.fixes,
    variables: after.variables - before.variables,
    epargne: after.epargne - before.epargne
  } : null,
  operations_appliquees: log,
  // Le JSON modifié n'est renvoyé QU'en mode apply et si valid
  finance_data_modifie: (!simulate && valid) ? financeData : null
};

return JSON.stringify(result, null, 2);

// ════════════════════════════════════════════════════════
// COMMITTER — POST save_data.php avec double garde "OUI"
// ════════════════════════════════════════════════════════
let input;
try {
  input = typeof query === 'string' ? JSON.parse(query) : query;
} catch (e) {
  return JSON.stringify({ error: 'JSON invalide' });
}

// ── GARDE 1 : paramètre confirmation="OUI" ──
if (!input.confirmation || String(input.confirmation).toUpperCase().trim() !== 'OUI') {
  return JSON.stringify({
    error: 'REFUS : le paramètre `confirmation` doit être la chaîne "OUI" (majuscule). L\'utilisateur doit taper OUI dans le chat avant que tu appelles cet outil.'
  });
}

// ── GARDE 2 : le dernier message utilisateur DOIT contenir "OUI" ──
const normalized = $('Normalize Input').first().json;
const lastUserMsg = (normalized.question || '').toUpperCase();
if (!/\bOUI\b/.test(lastUserMsg)) {
  return JSON.stringify({
    error: 'REFUS : le dernier message utilisateur ne contient pas "OUI". Demande confirmation avant de relancer.'
  });
}

// ── GARDE 3 : finance_data valide ──
if (!input.finance_data || typeof input.finance_data !== 'object' ||
    !input.finance_data.donneesAnnuelles) {
  return JSON.stringify({ error: 'finance_data invalide ou structure manquante.' });
}

// ── POST save_data.php ──
const url = 'https://charifmo.com/finance/save_data.php';
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url,
    body: input.finance_data,
    json: true,
    headers: { 'Content-Type': 'application/json' },
    timeout: 15000
  });
  return JSON.stringify({
    status: 'ok',
    committed: true,
    server_response: resp
  });
} catch (e) {
  return JSON.stringify({
    status: 'error',
    committed: false,
    error: e.message
  });
}
